  ('science', '1', 2, '1.plants', NULL, 'Which part of a plant takes in water from the soil?', '["Flower","Leaves","Petals","Roots"]', 3, 'Roots soak up water and hold the plant in the ground.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which part of a plant makes seeds?', '["Stem","Soil","Roots","Flower"]', 3, 'Flowers make seeds that can grow into new plants.', 10),
