  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "Devon checked the sky, grabbed his coat, and tucked an umbrella under his arm before leaving." What can you INFER?', '["He forgot his shoes","He is going to bed","It might rain","It is summer"]', 2, 'The coat and umbrella are clues that Devon expects rain — that is an inference.', 15),
  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "The library was silent except for the soft turn of pages and a distant cough." The mood of this scene is:', '["loud and wild","funny","scary","calm and quiet"]', 3, 'Details like silence and softly turning pages create a calm, quiet mood.', 15),
  ('reading', '5', 3, '5.infer', 'ELA.5.R.2', 'Read: "Scientists studied the coral for years and warned that warmer water harms it." The author wrote this mainly to:', '["inform","entertain","sell something","tell a story"]', 0, 'The passage shares facts and findings, so its purpose is to inform.', 15),
  ('science', '5', 2, '5.solar', NULL, 'What is at the center of our solar system?', '["Jupiter","The Moon","The Sun","The Earth"]', 2, 'The Sun is at the center; the planets orbit it.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet do we live on?', '["Saturn","Venus","Mars","Earth"]', 3, 'We live on Earth, the third planet from the Sun.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Planets move around the Sun in paths called ___.', '["tunnels","rivers","orbits","shadows"]', 2, 'An orbit is the path a planet takes around the Sun.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which is the largest planet in our solar system?', '["Jupiter","Mars","Earth","Mercury"]', 0, 'Jupiter is the biggest planet.', 10),
  ('science', '5', 2, '5.solar', NULL, 'The Sun is a ___.', '["star","moon","planet","comet"]', 0, 'The Sun is the star at the center of our solar system.', 10),
  ('science', '5', 2, '5.solar', NULL, 'Which planet is known as the ''Red Planet''?', '["Venus","Neptune","Mars","Saturn"]', 2, 'Mars looks reddish, so it''s called the Red Planet.', 10),
  ('science', '5', 2, '5.matter', NULL, 'The tiny particles that make up all matter are too small to ___.', '["matter","see with your eyes","move","be real"]', 1, 'Matter is made of tiny particles far too small to see.', 10),
  ('science', '5', 2, '5.matter', NULL, 'A change where no new substance forms, like melting, is a ___ change.', '["living","physical","magical","chemical"]', 1, 'Melting is a physical change — it''s still the same substance.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Burning wood into ash and smoke is a ___ change.', '["frozen","chemical","reversible","physical"]', 1, 'Burning makes new substances, so it''s a chemical change.', 10),
  ('science', '5', 2, '5.matter', NULL, 'When matter changes state, the amount of matter (its mass) ___.', '["becomes light","disappears","stays the same","doubles"]', 2, 'Mass is conserved — it stays the same when matter changes state.', 10),
  ('science', '5', 2, '5.matter', NULL, 'In which state are the particles packed most tightly?', '["Gas","Liquid","Steam","Solid"]', 3, 'In a solid, particles are packed tightly together.', 10),
  ('science', '5', 2, '5.matter', NULL, 'Mixing things that can be separated again makes a ___.', '["gas only","brand-new substance forever","chemical reaction","mixture"]', 3, 'A mixture can usually be separated back into its parts.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'An object at rest stays at rest unless a ___ acts on it.', '["force","sound","shadow","color"]', 0, 'It takes a force to start a still object moving.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'The force that pulls objects toward the Earth is ___.', '["gravity","sound","magnetism only","friction"]', 0, 'Gravity pulls objects toward Earth.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'Which force resists motion when two surfaces rub together?', '["Sound","Magnetism","Gravity","Friction"]', 3, 'Friction acts against motion between rubbing surfaces.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'To make a moving cart speed up, you apply a force in the ___ of motion.', '["direction","sound","opposite","color"]', 0, 'A force in the direction of motion speeds an object up.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'A heavier object needs ___ force to start moving than a lighter one.', '["more","no","less","zero"]', 0, 'More mass needs more force to move.', 10),
  ('science', '5', 2, '5.forcemotion', NULL, 'A push or pull that can change an object''s speed or direction is a ___.', '["force","mineral","season","habitat"]', 0, 'A force changes how an object moves.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'The original source of energy for almost all food chains is the ___.', '["soil","moon","wind","Sun"]', 3, 'The Sun''s energy starts nearly every food chain.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Plants that make their own food are called ___.', '["producers","decomposers","consumers","predators"]', 0, 'Producers (plants) make their own food using sunlight.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that eats only plants is a ___.', '["producer","carnivore","herbivore","decomposer"]', 2, 'Herbivores eat only plants.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'An animal that eats other animals is a ___.', '["herbivore that eats grass","producer","carnivore","plant"]', 2, 'Carnivores eat other animals.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'Which break down dead plants and animals and return nutrients to the soil?', '["Decomposers","Herbivores","Producers","The Sun"]', 0, 'Decomposers, like fungi, recycle nutrients back to the soil.', 10),
  ('science', '5', 2, '5.foodweb', NULL, 'In a food chain, energy passes from one living thing to the ___.', '["Sun","air","next","soil only"]', 2, 'Energy moves from one living thing to the next in a food chain.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which organ pumps blood through your body?', '["The lungs","The heart","The brain","The stomach"]', 1, 'The heart pumps blood all around your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'Which organs take in oxygen when you breathe?', '["The heart","The kidneys","The lungs","The liver"]', 2, 'The lungs bring oxygen into your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'The brain is the main organ of the ___ system.', '["digestive","skeletal","nervous","muscular"]', 2, 'The brain and nerves make up the nervous system.', 10),
  ('science', '5', 2, '5.body', NULL, 'Your ___ give your body shape and help it move.', '["fingernails","hair","bones","freckles"]', 2, 'Bones (the skeleton) support and move your body.', 10),
  ('science', '5', 2, '5.body', NULL, 'Food is broken down in your ___ system.', '["digestive","nervous","skeletal","breathing"]', 0, 'The digestive system breaks down food.', 10),
  ('science', '5', 2, '5.body', NULL, 'Blood carries ___ to all parts of your body.', '["only water","oxygen and nutrients","sound","only air bubbles"]', 1, 'Blood delivers oxygen and nutrients to your cells.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The change from liquid water to water vapor is called ___.', '["precipitation","evaporation","condensation","freezing"]', 1, 'Evaporation turns liquid water into vapor.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The change from water vapor back to liquid, forming clouds, is ___.', '["precipitation","melting","condensation","evaporation"]', 2, 'Condensation forms cloud droplets from vapor.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Most of Earth''s water is found in the ___.', '["underground only","oceans","clouds","rivers"]', 1, 'Oceans hold most of Earth''s water.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Water that soaks down into the ground becomes ___.', '["a cloud","groundwater","vapor right away","a rock"]', 1, 'Water that sinks into the ground is called groundwater.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'The water cycle recycles Earth''s water over and over, powered by the ___.', '["ground","moon","wind only","Sun"]', 3, 'The Sun''s energy keeps the water cycle going.', 10),
  ('science', '5', 2, '5.watercycle', NULL, 'Rain, snow, sleet, and hail are all forms of ___.', '["condensation","precipitation","evaporation","groundwater"]', 1, 'All water falling from the sky is precipitation.', 10);
